import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import NotificationBell from '../components/NotificationBell';
import {
  getWaitingPatients, getPastPatients, getPatientHistory,
  recordVitals, submitDiagnosis, setDoctorInactive,
  requestUnavailability, getDoctorUnavailabilityRequests,
} from '../api';

// Replaces: templates/doctor.html + static/components/doctor.js

const TABS = ['Waiting Patients', 'Past Patients', 'Unavailability'];

export default function Doctor() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab]                   = useState(0);
  const [waiting, setWaiting]           = useState([]);
  const [past, setPast]                 = useState([]);
  const [unavailReqs, setUnavailReqs]   = useState([]);
  const [selectedPatient, setSelected]  = useState(null);
  const [history, setHistory]           = useState([]);
  const [vitals, setVitals]             = useState({ bp_systolic:'', bp_diastolic:'', temperature:'', pulse:'' });
  const [diagnosis, setDiagnosis]       = useState({ diagnosis:'', prescription:'', notes:'' });
  const [unavailForm, setUnavailForm]   = useState({ start_datetime:'', end_datetime:'', reason:'' });
  const [msg, setMsg]                   = useState('');

  const doctor_id = user.doctor_id;

  useEffect(() => { fetchWaiting(); }, []);

  const fetchWaiting = async () => {
    const data = await getWaitingPatients(doctor_id);
    setWaiting(data.patients || []);
  };

  const fetchPast = async () => {
    const data = await getPastPatients(doctor_id);
    setPast(data.patients || []);
  };

  const fetchUnavailReqs = async () => {
    const data = await getDoctorUnavailabilityRequests(doctor_id);
    setUnavailReqs(data.requests || []);
  };

  const handleTab = (i) => {
    setTab(i);
    if (i === 1) fetchPast();
    if (i === 2) fetchUnavailReqs();
  };

  const handleSelectPatient = async (p) => {
    setSelected(p);
    const data = await getPatientHistory(p.patient_id);
    setHistory(data.history || []);
  };

  const handleRecordVitals = async (appointment_id) => {
    await recordVitals(selectedPatient.patient_id, vitals);
    flash('Vitals recorded.');
  };

  const handleSubmitDiagnosis = async (appointment_id) => {
    await submitDiagnosis({ appointment_id, ...diagnosis });
    flash('Diagnosis submitted.');
    setSelected(null);
    fetchWaiting();
  };

  const handleGoOffline = async () => {
    if (!window.confirm('Set yourself offline? This will deactivate your schedule.')) return;
    await setDoctorInactive(doctor_id);
    flash('Status set to inactive.');
  };

  const handleUnavailRequest = async (e) => {
    e.preventDefault();
    await requestUnavailability({ doctor_id, ...unavailForm });
    flash('Unavailability request submitted.');
    setUnavailForm({ start_datetime:'', end_datetime:'', reason:'' });
    fetchUnavailReqs();
  };

  const handleLogout = () => { logout(); navigate('/login'); };
  const flash = (m) => { setMsg(m); setTimeout(() => setMsg(''), 3000); };

  return (
    <div style={s.page}>
      {/* HEADER */}
      <header style={s.header}>
        <div style={s.headerLeft}>
          <span style={s.logo}>💊 CareLine</span>
          <span style={s.role}>Doctor Portal</span>
        </div>
        <div style={s.headerRight}>
          <span style={s.welcome}>Dr. {user.name}</span>
          <NotificationBell role="doctor" userId={doctor_id} />
          <button style={s.offlineBtn} onClick={handleGoOffline}>Go Offline</button>
          <button style={s.logoutBtn} onClick={handleLogout}>Logout</button>
        </div>
      </header>

      {msg && <div style={s.flash}>{msg}</div>}

      {/* TABS */}
      <nav style={s.tabs}>
        {TABS.map((t, i) => (
          <button key={t} style={tab === i ? s.tabActive : s.tab} onClick={() => handleTab(i)}>{t}</button>
        ))}
      </nav>

      <main style={s.main}>
        {/* TAB 0: WAITING PATIENTS */}
        {tab === 0 && (
          <div style={s.splitPane}>
            <div style={s.leftPane}>
              <h3>Waiting Queue ({waiting.length})</h3>
              {waiting.length === 0 && <p style={s.empty}>No patients waiting.</p>}
              {waiting.map(p => (
                <div key={p.id} style={{ ...s.card, background: selectedPatient?.id === p.id ? '#e8f0fe' : 'white' }}
                  onClick={() => handleSelectPatient(p)}>
                  <strong>#{p.ticket_no} — {p.patient_name}</strong>
                  <div style={s.meta}>Age: {p.age} | {p.gender} | {p.contact}</div>
                </div>
              ))}
            </div>

            <div style={s.rightPane}>
              {selectedPatient ? (
                <>
                  <h3>Patient: {selectedPatient.patient_name}</h3>

                  <section style={s.section}>
                    <h4>Record Vitals</h4>
                    <div style={s.grid2}>
                      {['bp_systolic','bp_diastolic','temperature','pulse'].map(k => (
                        <label key={k} style={s.label}>
                          {k.replace('_',' ')}
                          <input style={s.input} value={vitals[k]}
                            onChange={e => setVitals(v => ({ ...v, [k]: e.target.value }))} />
                        </label>
                      ))}
                    </div>
                    <button style={s.btn} onClick={() => handleRecordVitals(selectedPatient.id)}>
                      Save Vitals
                    </button>
                  </section>

                  <section style={s.section}>
                    <h4>Submit Diagnosis</h4>
                    <label style={s.label}>Diagnosis
                      <textarea style={s.textarea} rows={3} value={diagnosis.diagnosis}
                        onChange={e => setDiagnosis(d => ({ ...d, diagnosis: e.target.value }))} />
                    </label>
                    <label style={s.label}>Prescription
                      <textarea style={s.textarea} rows={3} value={diagnosis.prescription}
                        onChange={e => setDiagnosis(d => ({ ...d, prescription: e.target.value }))} />
                    </label>
                    <label style={s.label}>Notes
                      <textarea style={s.textarea} rows={2} value={diagnosis.notes}
                        onChange={e => setDiagnosis(d => ({ ...d, notes: e.target.value }))} />
                    </label>
                    <button style={s.btn} onClick={() => handleSubmitDiagnosis(selectedPatient.id)}>
                      Complete Appointment
                    </button>
                  </section>

                  <section style={s.section}>
                    <h4>Appointment History</h4>
                    {history.length === 0 && <p style={s.empty}>No previous visits.</p>}
                    {history.map(h => (
                      <div key={h.id} style={s.historyCard}>
                        <div><strong>{new Date(h.created_at).toLocaleDateString()}</strong> — {h.clinic_name}</div>
                        <div>Diagnosis: {h.diagnosis || '—'}</div>
                        <div>Prescription: {h.prescription || '—'}</div>
                      </div>
                    ))}
                  </section>
                </>
              ) : (
                <p style={s.empty}>Select a patient from the queue to begin.</p>
              )}
            </div>
          </div>
        )}

        {/* TAB 1: PAST PATIENTS */}
        {tab === 1 && (
          <div>
            <h3>Past Patients ({past.length})</h3>
            <table style={s.table}>
              <thead><tr>
                <th style={s.th}>Name</th><th style={s.th}>Age</th>
                <th style={s.th}>Gender</th><th style={s.th}>Last Visit</th>
                <th style={s.th}>Last Diagnosis</th>
              </tr></thead>
              <tbody>
                {past.map(p => (
                  <tr key={p.id}>
                    <td style={s.td}>{p.name}</td>
                    <td style={s.td}>{p.age}</td>
                    <td style={s.td}>{p.gender}</td>
                    <td style={s.td}>{new Date(p.last_visit).toLocaleDateString()}</td>
                    <td style={s.td}>{p.diagnosis || '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* TAB 2: UNAVAILABILITY */}
        {tab === 2 && (
          <div style={s.twoCol}>
            <div>
              <h3>Request Unavailability</h3>
              <form onSubmit={handleUnavailRequest} style={s.formCol}>
                <label style={s.label}>Start Date & Time
                  <input style={s.input} type="datetime-local" value={unavailForm.start_datetime}
                    onChange={e => setUnavailForm(f => ({ ...f, start_datetime: e.target.value }))} required />
                </label>
                <label style={s.label}>End Date & Time
                  <input style={s.input} type="datetime-local" value={unavailForm.end_datetime}
                    onChange={e => setUnavailForm(f => ({ ...f, end_datetime: e.target.value }))} required />
                </label>
                <label style={s.label}>Reason
                  <textarea style={s.textarea} rows={3} value={unavailForm.reason}
                    onChange={e => setUnavailForm(f => ({ ...f, reason: e.target.value }))} required />
                </label>
                <button style={s.btn} type="submit">Submit Request</button>
              </form>
            </div>
            <div>
              <h3>My Requests</h3>
              {unavailReqs.length === 0 && <p style={s.empty}>No requests yet.</p>}
              {unavailReqs.map(r => (
                <div key={r.id} style={s.card}>
                  <div>{new Date(r.start_datetime).toLocaleDateString()} — {new Date(r.end_datetime).toLocaleDateString()}</div>
                  <div style={s.meta}>{r.reason}</div>
                  <span style={{ ...s.badge, background: r.status === 'approved' ? '#4caf50' : r.status === 'rejected' ? '#f44336' : '#ff9800' }}>
                    {r.status}
                  </span>
                  {r.admin_comment && <div style={s.meta}>Admin: {r.admin_comment}</div>}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

const s = {
  page: { minHeight:'100vh', background:'#f4f6fb', fontFamily:'Segoe UI,sans-serif' },
  header: { background:'#1a73e8', color:'white', padding:'0 24px', display:'flex', alignItems:'center', justifyContent:'space-between', height:56 },
  headerLeft: { display:'flex', alignItems:'center', gap:12 },
  headerRight: { display:'flex', alignItems:'center', gap:12 },
  logo: { fontWeight:700, fontSize:'1.1rem' },
  role: { background:'rgba(255,255,255,.2)', padding:'2px 10px', borderRadius:12, fontSize:'.8rem' },
  welcome: { fontSize:'.9rem' },
  offlineBtn: { padding:'5px 12px', borderRadius:6, border:'1px solid white', background:'transparent', color:'white', cursor:'pointer', fontSize:'.85rem' },
  logoutBtn: { padding:'5px 12px', borderRadius:6, border:'none', background:'rgba(255,255,255,.2)', color:'white', cursor:'pointer', fontSize:'.85rem' },
  flash: { background:'#4caf50', color:'white', padding:'10px 24px', textAlign:'center', fontWeight:600 },
  tabs: { display:'flex', gap:0, background:'white', borderBottom:'1px solid #e0e0e0', padding:'0 24px' },
  tab: { padding:'12px 20px', border:'none', background:'none', cursor:'pointer', color:'#666', fontSize:'.9rem', borderBottom:'3px solid transparent' },
  tabActive: { padding:'12px 20px', border:'none', background:'none', cursor:'pointer', color:'#1a73e8', fontSize:'.9rem', fontWeight:700, borderBottom:'3px solid #1a73e8' },
  main: { padding:24, maxWidth:1200, margin:'0 auto' },
  splitPane: { display:'flex', gap:24 },
  leftPane: { width:300, flexShrink:0 },
  rightPane: { flex:1 },
  card: { background:'white', borderRadius:10, padding:'12px 16px', marginBottom:10, cursor:'pointer', boxShadow:'0 1px 4px rgba(0,0,0,.08)', border:'1px solid #eee' },
  meta: { fontSize:'.8rem', color:'#888', marginTop:4 },
  section: { background:'white', borderRadius:10, padding:16, marginBottom:16, boxShadow:'0 1px 4px rgba(0,0,0,.06)' },
  grid2: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 },
  label: { display:'flex', flexDirection:'column', fontSize:'.85rem', fontWeight:600, color:'#555', gap:4 },
  input: { padding:'8px 10px', borderRadius:6, border:'1px solid #ddd', fontSize:'.9rem' },
  textarea: { padding:'8px 10px', borderRadius:6, border:'1px solid #ddd', fontSize:'.9rem', resize:'vertical' },
  btn: { marginTop:12, padding:'9px 18px', borderRadius:7, border:'none', background:'#1a73e8', color:'white', fontWeight:600, cursor:'pointer' },
  table: { width:'100%', borderCollapse:'collapse', background:'white', borderRadius:10, overflow:'hidden', boxShadow:'0 1px 4px rgba(0,0,0,.06)' },
  th: { background:'#f0f4ff', padding:'10px 14px', textAlign:'left', fontSize:'.85rem', color:'#444', fontWeight:600 },
  td: { padding:'10px 14px', borderBottom:'1px solid #f0f0f0', fontSize:'.85rem' },
  empty: { color:'#aaa', fontStyle:'italic', padding:12 },
  historyCard: { background:'#f9f9f9', borderRadius:8, padding:'10px 14px', marginBottom:8, fontSize:'.85rem', lineHeight:1.6 },
  twoCol: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:24 },
  formCol: { display:'flex', flexDirection:'column', gap:12 },
  badge: { display:'inline-block', color:'white', borderRadius:12, padding:'2px 10px', fontSize:'.75rem', fontWeight:600, marginTop:6 },
};
